sql:
SELECT event_id, sound_type
FROM sound_events
WHERE source_id = 1 AND sound_type = 'noise';

SELECT frequency_range, intensity
FROM sound_events
WHERE sound_type = 'Alarm' AND source_id = 1;

SELECT event_id, source_id, timestamp, location, sound_type, intensity, model_id, is_analyzed, notes
FROM sound_events
WHERE event_id = 1;

SELECT AVG(intensity) AS average_intensity
FROM sound_events
WHERE timestamp LIKE '2023-10-01%';

SELECT DISTINCT location_name 
FROM locations 
WHERE altitude > 5;

SELECT event_id, sound_type
FROM sound_events
WHERE duration > (
  SELECT AVG(duration)
  FROM sound_events
);

SELECT type_name 
FROM sound_types 
WHERE is_predefined = 1;

SELECT event_id 
   FROM sound_data 
   WHERE data_value > 200;

SELECT type_name 
FROM sound_types 
WHERE type_id = 0;

SELECT source_name, contact_email
FROM sound_sources
WHERE status = 'active';

SELECT DISTINCT sound_type
FROM sound_events
WHERE location = 'Location A';

SELECT DISTINCT type_name 
FROM sound_types 
WHERE is_predefined = 0;

SELECT sound_type, COUNT(*) 
FROM sound_events 
GROUP BY sound_type;

external_knowledge:
- 'identifiers' refers to the unique identifiers (`event_id`) for each sound event;
- 'the guesses about the nature of the sounds' corresponds to the `predicted_type` of each sound event;
- 'occurrences that have been analyzed' means the events that have entries in both the `sound_events` and `model_predictions` tables, indicating that predictions have been made for these events.

sql:
SELECT se.event_id, mp.predicted_type
FROM sound_events se
INNER JOIN model_predictions mp ON se.event_id = mp.event_id;

SELECT source_name, contact_email
FROM sound_sources
WHERE source_id = 0;

SELECT * 
FROM sound_events 
JOIN sound_sources ON sound_events.source_id = sound_sources.source_id;

SELECT *
FROM sound_events
WHERE intensity > (SELECT AVG(intensity) FROM sound_events);

SELECT COUNT(*) 
FROM sound_event_versions 
WHERE event_id = 'Event ID';
